module top_module(
    input [3:0] obf_A,
    input [3:0] B,
    input SUB,
    output reg [3:0] SUM,
    output reg CARRY
);always @(*) begin
        if (SUB) begin
            SUM <= obf_A - B;
            CARRY <= (obf_A < B);
        end else begin
            SUM <= obf_A + B;
            CARRY <= (SUM < obf_A);
        end
    end

endmodule
